class Solution {
public:
	bool isStableSubarray(int size, vector<int> &nums) {
		if (size == 1) return true;
		int counter = 0;
		for (int i = size - 1; i < nums.size(); ++i) {
			if (nums[i] >= nums[i - 1]) counter = 0;
			else counter = 1;
			if (counter == 1) continue;
		}
		return true;
	}
};

